import Izq from "../icons/left-arrow.png";
import Der from "../icons/right-arrow.png";
import CabanaGallery from "./CabañaGallery.jsx";
import Photos from "./Fotos.jsx";
import Datos from "./DatosCabaña.jsx";
import Wave from "../DecorationComponents/OndaCabañaSlider";

const Cabañas = () => {
  return (
    <div className=" h-screen snap-start overflow-hidden ">
    <section className="h-[100vh] bg-[#D8C4A5] content-center justify-center ">
      <div className="relative flex w-[55%] mx-auto gap-[2vh]">
        <button className="">
          <img src={Izq} className="w-[30vh] h-auto" />
        </button>
        <div className="bg-white rounded-[24px] p-[3vh] flex">
          <CabanaGallery photos={Photos} />
          <Datos />
        </div>
        <button>
          <img src={Der} className="w-[30vh] h-auto" />
        </button>
      </div>
      
    </section>
    <div className="bg-white bottom-0 left-0 w-full">
        <Wave />
      </div>
    </div>
  );
};

export default Cabañas;
